insert into public.memory_chunks (id, document_id, chunk_index, chunk_text, token_count, embedding_model, embedding, metadata) values ('8cca60d7-01b1-528a-892b-73c6d52927d0', '7890d799-c232-57d7-a54e-03be262b2be8', 0, '# MEMORY.md

Каноническая долговременная память для AI-office.

Правила:
- писать только стабильные, полезные, проверяемые факты;
- не писать секреты, токены, пароли, API keys, cookie, bearer values;
- не тащить сюда сырой лог, длинные дампы и одноразовый шум;
- всё спорное сначала проходит через daily notes / Dreaming / review.

## Пользователь
- Имя: Темыч.
- Предпочтительный язык общения: русский.
- Предпочитаемый стиль: прямой, спокойный, инженерный, без бюрократии и фальшивой уверенности.
- Ожидание от ассистента: вести себя как Jarvis-like AI office — не просто отвечать, а превращать идеи в планы, решения, артефакты и проверяемые результаты.

## Рабочие правила
- Не говорить, что что-то готово, пока это не проверено.
- Для важных решений показывать default option, альтернативу, trade-offs, критерий готовности и способ проверки.
- Для дебага давать полный исправленный путь: что сломано, как чинить, как проверить, что делать если снова сломается.
- Предпочитать простые и наблюдаемые решения перед лишними сервисами и сложностью.
- Важный контекст нужно сохранять в файлы и артефакты, а не только в чат.

## Устойчивые инфраструктурные факты
- Основной workspace: `/opt/openclaw-stack/workspace`.
- OpenClaw Office опубликован через nginx по пути `/office/`.
- Grafana опубликована через nginx по пути `/grafana/`.
- Telegram voice/STT работает через built-in media audio pipeline OpenClaw.
- Текущая рабочая STT-конфигурация для Telegram использует провайдера `groq` и модель `whisper-large-v3-turbo`.', 274, 'nomic-embed-text', '[-0.04130689,0.02414532,-0.14641460,0.01378397,0.02429203,-0.04148438,0.00561575,-0.00392457,0.00567172,-0.05864993,-0.02272055,0.00462809,0.08239140,0.02231053,0.00693186,-0.03932102,-0.01426515,-0.06657694,-0.07547741,0.06099488,-0.01826883,-0.01197426,-0.01647789,-0.07287005,0.07603469,0.06539208,0.07146261,0.01101095,-0.01859041,0.02263784,-0.02405124,-0.02448766,-0.02638293,-0.03752738,-0.03019252,-0.02671830,0.04840491,0.05065714,-0.00408649,-0.00201124,0.03397910,-0.00111170,0.00865496,-0.03151209,0.03468158,0.00647447,-0.01325652,0.01383862,0.07933444,-0.03786028,0.01589112,0.00434360,0.06549615,-0.02320299,0.09190540,-0.00319714,-0.01568817,-0.01288750,0.03981923,0.01612701,0.10219050,0.04187097,0.00365247,0.06868547,0.07323249,-0.05690793,-0.00115288,0.02711608,-0.01761303,-0.06575491,0.06519958,-0.00245579,0.01927273,0.02289261,-0.03490758,-0.04143228,-0.05901981,-0.02749874,0.02683003,-0.01179640,0.03910864,0.00050516,0.08411083,0.00137604,0.06361208,-0.02826306,-0.02874077,-0.03797893,-0.01792266,0.07581486,-0.00520431,-0.01629332,0.02251556,0.03520067,-0.03983869,0.08060183,0.03582998,0.01598234,-0.01010758,-0.05723201,-0.01043813,-0.01056913,0.03097918,-0.00494011,0.05524789,0.02022002,-0.02408541,-0.00224100,-0.03887979,0.00360305,-0.02131201,0.07004623,0.00971490,-0.04208753,0.05292441,0.00110658,0.04965971,-0.05116734,0.02342844,0.02242985,-0.04740406,-0.04041608,0.00979089,0.00667859,0.04024851,-0.00164266,-0.05043701,-0.01169800,-0.00327317,-0.03133187,0.02562725,0.01939571,-0.03371502,-0.00638997,0.05468764,0.08060034,-0.01079909,-0.05068425,0.03002630,-0.02854833,0.01140706,0.02459118,-0.01532529,-0.04458210,-0.03167715,-0.03379242,0.02664518,-0.01235477,-0.06101970,0.04732440,0.00092116,0.01094747,-0.00248483,0.01455879,0.03469416,-0.04974268,-0.01145205,-0.01081659,0.00642054,0.03311261,-0.01889581,0.0462